#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    int *datos = NULL;

    printf("Cantidad de datos: ");
    scanf("%d", &n);

    if (n <= 0) {
        printf("El tamano debe ser positivo.\n");
        return 1;
    }

    datos = malloc((size_t)n * sizeof *datos);
    if (datos == NULL) {
        printf("No fue posible reservar memoria.\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        datos[i] = i * i;
    }

    printf("Ultimo valor: %d\n", datos[n - 1]);
    free(datos);
    datos = NULL;
    return 0;
}

